(function(){
  const ART = {
    genie:{
      name:"Winged Genie Fertilizing a Date Tree",
      sub:"Assyrian, about 2,900 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "This figure has wings like a bird but stands like a person. What do you think it is?",
        "Look at his hand. What do you think he is holding?"
      ],
      reveal:"This is called a winged genie. He is a magic helper spirit from a very old place called Assyria. That is part of the world we now call Iraq. He is blessing a date tree so it will grow. Dates were a very important food back then."
    },
    guanyin:{
      name:"Guanyin of the Southern Sea",
      sub:"Chinese, about 900 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "This person is sitting in a relaxed way. How do you think they feel?",
        "This statue has bright colors and patterns. What do you notice?"
      ],
      reveal:"This is Guanyin. She is a kind figure from Buddhism, a religion from Asia. People believe she listens when someone is sad or in trouble. She is sitting in a calm, easy pose, like she has all day just for you."
    },
    dusasa:{
      name:"Dusasa I",
      sub:"By El Anatsui, made in 2007",
      img:"data:image/jpeg;base64,",
      qs:[
        "Take a guess before I tell you. What do you think this giant artwork is made of?",
        "This is bigger than a school bus. Why do you think the artist made it so big?"
      ],
      reveal:"This is made of thousands of bottle caps from old liquor bottles. An artist named El Anatsui flattened them and sewed them together with wire. It weighs 350 pounds and is taller than a house. He turns trash into something that shines like cloth."
    },
    lion:{
      name:"Lion",
      sub:"Greek, about 2,300 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "How old do you think this lion is?",
        "Do you think the sculptor ever saw a real lion?"
      ],
      reveal:"This lion is about 2,300 years old. It comes from ancient Greece. Real lions used to live in parts of Greece back then, so the sculptor may have seen one, or talked to someone who did."
    },
    armor:{
      name:"Armor for Man and Horse",
      sub:"Italian, about 460 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "If you wore this on a big day, how would you feel? Brave? Nervous? Excited?",
        "Why do you think both the knight and the horse wear armor?"
      ],
      reveal:"Knights did not wear fancy armor like this for real battles. They wore it for parades and contests called jousts, kind of like a costume for a big show. Both the knight and the horse needed protection because the horse could get hurt too."
    },
    shiva:{
      name:"Shiva Nataraja, The Lord of Dance",
      sub:"Indian, about 800 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "Do you think this is a statue of a boy or a girl? What do you think they are doing?",
        "Look closely at the two earrings. Do you notice anything different about them?"
      ],
      reveal:"This is the Hindu god Shiva, dancing as the Lord of the Dance. Shiva is a boy, but look at his ears. One earring is a boy style and one is a girl style. That is on purpose. It shows that Shiva has both boy and girl energy all in one."
    },
    caravaggio:{
      name:"Saint John the Baptist in the Wilderness",
      sub:"By Caravaggio, about 420 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "How do you think he is feeling in this picture?",
        "What do you notice about the light and the shadows?"
      ],
      reveal:"This is Saint John the Baptist, painted by an artist named Caravaggio. He was famous for painting how people really feel instead of making them look perfect. A writer long ago said this painting made people go quiet when they looked at it. So if you felt something too, you are not alone."
    },
    monet:{
      name:"Boulevard des Capucines",
      sub:"By Claude Monet, about 150 years old",
      img:"data:image/jpeg;base64,",
      qs:[
        "This painting looks blurry and fast, not like a photo. Why do you think the artist painted it that way?",
        "What season do you think it is? How can you tell?"
      ],
      reveal:"Claude Monet painted this busy street in Paris from a friend's balcony. He worked fast to catch the feeling of one moment. Those blurry little dabs of paint are actually people walking. This kind of painting was so new that people made fun of it. They called Monet and his friends Impressionists, and that name stuck."
    }
  };

  const ORDER=['genie','guanyin','dusasa','lion','armor','shiva','caravaggio','monet'];

  function start(host, ctx){
    let visited = ctx.state.nelsonVisited || {};
    let current = null;
    let qIndex = 0;

    function allDone(){
      return ORDER.every(k=>visited[k]);
    }

    function renderGrid(){
      const doneCount = ORDER.filter(k=>visited[k]).length;
      host.innerHTML = `
        <div class="center">
          <p class="sub">Clover wants to explore the museum with you! Tap a piece of art to look closer.</p>
          <p class="sub"><strong>${doneCount} of ${ORDER.length}</strong> explored</p>
        </div>
        <div class="story-grid" id="artGrid"></div>
        <div class="center mt">
          <button class="btn ghost" id="doneBtn">\u2190 Map</button>
        </div>
      `;
      const grid = host.querySelector('#artGrid');
      ORDER.forEach(key=>{
        const a = ART[key];
        const tile = document.createElement('div');
        tile.className = 'story-pick';
        tile.style.cursor = 'pointer';
        tile.style.position = 'relative';
        tile.innerHTML = `
          <img src="${a.img}" alt="${a.name}" style="width:100%;border-radius:10px;display:block;${visited[key] ? '' : 'filter:none;'}" />
          <div style="font-weight:700;margin-top:6px;">${a.name}</div>
          ${visited[key] ? '<div style="position:absolute;top:6px;right:6px;font-size:22px;">\u2705</div>' : ''}
        `;
        tile.addEventListener('click', ()=>openArt(key));
        grid.appendChild(tile);
      });
      host.querySelector('#doneBtn').addEventListener('click', ()=>{
        if(allDone() && !ctx.state.nelsonStarEarned){
          ctx.state.nelsonStarEarned = true;
          ctx.award({coins:10, star:true, treat:true});
          ctx.confetti && ctx.confetti();
          ctx.toast && ctx.toast("You explored the whole museum with Clover! \uD83E\uDD67");
        }
        ctx.close();
      });
    }

    function openArt(key){
      current = key;
      qIndex = 0;
      renderQuestion();
    }

    function renderQuestion(){
      const a = ART[current];
      const q = a.qs[qIndex];
      host.innerHTML = `
        <div class="center">
          <img src="${a.img}" alt="${a.name}" style="max-width:280px;max-height:320px;border-radius:12px;box-shadow:0 4px 14px rgba(0,0,0,0.25);" />
          <h3 class="h3">${a.name}</h3>
          <p class="sub">${a.sub}</p>
        </div>
        <div class="mt">
          <p class="bigproblem" style="font-size:1.1rem;">${q}</p>
          <input type="text" class="answer-input" id="artAnswer" placeholder="Type what you think..." autocomplete="off" />
          <div class="center mt">
            <button class="btn teal" id="revealBtn">Tell Clover!</button>
          </div>
        </div>
        <div id="fbArea" class="mt"></div>
      `;
      const input = host.querySelector('#artAnswer');
      const revealBtn = host.querySelector('#revealBtn');
      input.focus();

      function reveal(){
        const fb = host.querySelector('#fbArea');
        const isLastQ = qIndex === a.qs.length - 1;
        fb.innerHTML = `
          <div class="fb ok">
            <img src="${ctx.clover.cele}" alt="Clover" style="width:48px;vertical-align:middle;margin-right:8px;" />
            ${isLastQ ? a.reveal : "Good thinking! Here's another question about this one:"}
          </div>
          <div class="center mt">
            <button class="btn green" id="nextBtn">${isLastQ ? 'Next artwork \u2192' : 'Next question \u2192'}</button>
          </div>
        `;
        revealBtn.disabled = true;
        input.disabled = true;
        host.querySelector('#nextBtn').addEventListener('click', ()=>{
          if(isLastQ){
            visited[current] = true;
            ctx.state.nelsonVisited = visited;
            ctx.award({coins:2});
            renderGrid();
          }else{
            qIndex++;
            renderQuestion();
          }
        });
      }

      revealBtn.addEventListener('click', reveal);
      input.addEventListener('keydown', (e)=>{
        if(e.key === 'Enter') reveal();
      });
    }

    renderGrid();
  }

  window.Stops.register('6D', { name:'Nelson-Atkins', start });
})();
